// // This module is designed for a 14-bit addressable single-bit RAM block that operates on the falling edge of the clock signal (clka). The module features a write disable signal (wena); when this signal is high, data (dinb) cannot be written into the memory location specified by the address (addrb). Conversely, when the write disable is low, the module outputs the data stored at the specified address ( doutb ).
module top_module(douta,
    clka,
    addra,
    dina,
    wea);output reg [0:0] douta; // changed to output reg
  input clka;
  input [13:0] addra;
  input [0:0] dina;
  input [0:0] wea;

  reg [0:0] mem[0:16383]; // 14-bit addressable memory block

  always @(posedge clka) begin
    if (wea) begin // write operation
      mem[addra] <= dina;
    end else begin // read operation
      douta <= mem[addra];
    end
  end
endmodule
